export const guidelinesContent: Record<string, string> = {
  "accessibility-baseline": "# Accessibility Baseline\n\nAccessibility is not a polish pass. It is part of the minimum acceptable quality.\n\n## Core Principle\n\nThe default output should be usable, legible, and operable without special pleading.\n\n## Color Contrast\n\nMeet at least AA contrast for normal UI text.\n\n- body text should have sufficient contrast against its background\n- muted text can be softer, but still readable\n- semantic surfaces should not hide labels or metadata\n\nDo not use subtlety as an excuse for unreadable UI.\n\n## Non-Text Contrast\n\nInteractive or meaningful boundaries should still be visible.\n\n- inputs should look like inputs\n- selected items should read as selected\n- cards and panels should separate clearly enough from the background\n\nIf a reviewer has to squint to understand hierarchy, contrast is too weak.\n\n## Touch Target And Control Size\n\nInteractive controls should respect practical target size.\n\n- aim for at least `44x44`\n- do not create tiny pills or buttons that only look clickable\n\nCompact UI still needs usable targets.\n\n## Labeling Rule\n\nDo not rely on color alone.\n\n- warnings need text or icon support\n- states should have a label, not just a fill change\n- icons that carry meaning should have text support unless the pattern is universally obvious\n\n## Text Hierarchy\n\nReadable hierarchy requires:\n\n- clear title sizes\n- readable body text\n- supporting copy that is visibly secondary but still legible\n\nIf hierarchy depends only on tiny font size changes, it is too weak.\n\n## Form Rule\n\nInputs should provide:\n\n- clear label\n- visible field boundary\n- helper or error text when needed\n\nDo not hide critical form meaning in placeholder text alone.\n\n## Checklist\n\nBefore considering accessibility acceptable, verify:\n\n1. Does body text meet practical contrast expectations?\n2. Are interactive boundaries visible enough?\n3. Are controls large enough to use?\n4. Are status and state communicated by more than color?\n5. Are labels and helpers present where needed?\n\nIf the answer to any of these is no, the design is not ready.\n\n## Figma and Vibma Notes\n\nWhen working through Vibma:\n\n- run focused contrast lint\n- review dark and light modes separately\n- check both text contrast and practical non-text visibility\n- do not stop at zero hardcoded colors; that is not the same as accessibility\n\nAn accessible baseline is the floor, not the stretch goal.",
  "auto-layout-and-constraints": "# Auto-Layout And Constraints\n\nMost UI should be auto-layout first. Manual positioning is the exception.\n\n## Core Principle\n\nContainers should describe relationships, not frozen coordinates.\n\n- use auto-layout for UI structure\n- use constraints only where non-auto-layout behavior is intentional\n- avoid absolute positioning for normal product UI\n\n## Default Rule\n\nIf a frame contains UI content, it should usually be auto-layout.\n\nTypical auto-layout containers:\n\n- page shells\n- sidebars\n- topbars\n- forms\n- cards\n- rows\n- stacks\n- panels\n\nIf a frame is only being used as a visual box with manually placed children, it is probably under-structured.\n\n## Sizing Rule\n\nUse sizing intentionally:\n\n- `FIXED` for shell boundaries and true fixed dimensions\n- `FILL` for structural children that should adapt to the parent\n- `HUG` for content-sized leaves and compact groups\n\nDo not use `FIXED` on a child inside auto-layout just because it looked right once.\n\n## Alignment Rule\n\nUse the parent layout to create alignment.\n\n- use padding instead of manual offsets\n- use item spacing instead of visual guessing\n- use `SPACE_BETWEEN` only when the layout meaningfully calls for it\n\nIf alignment depends on manual nudging, the structure is weak.\n\n## Common Patterns\n\nSidebar shell:\n\n- sidebar width: `FIXED`\n- main content: `FILL`\n\nTopbar:\n\n- shell width: `FILL`\n- title group: `HUG` or `FILL` depending on content\n- action group: `HUG`\n\nCard list:\n\n- list stack: `FILL`\n- card: `FILL`\n- internal content uses vertical stacks\n\nForm:\n\n- field stack: `FILL`\n- label and helper text wrap within the field width\n- buttons usually sit in a separate action row\n\n## Absolute Positioning Rule\n\nUse absolute positioning sparingly.\n\nGood uses:\n\n- decorative backgrounds\n- overlays inside a controlled component\n- badges or markers intentionally anchored in a card corner\n\nBad uses:\n\n- normal labels, buttons, fields, and rows\n- screen layout that should respond to width or content changes\n\n## Constraint Rule\n\nConstraints matter when a node is inside a non-auto-layout parent.\n\nUse them intentionally for:\n\n- scalable hero art\n- anchored decoration\n- special overlays\n\nDo not rely on constraints to replace missing auto-layout structure.\n\n## Checklist\n\nBefore considering layout done, verify:\n\n1. Are all main UI containers auto-layout?\n2. Are padding and spacing defined by layout, not eyeballing?\n3. Are structural children using `FILL` where appropriate?\n4. Is absolute positioning limited to deliberate exceptions?\n5. Does the layout survive content changes and parent resizing?\n\nIf the answer to any of these is no, the layout is not robust enough.\n\n## Figma and Vibma Notes\n\nWhen updating layout through Vibma:\n\n- prefer layout properties on frames instead of manual `x` and `y` for internal UI\n- use nested `layout` patches for sizing and spacing updates\n- remember that `FILL` only works for children inside an auto-layout parent\n- verify after large batch updates because a successful write is not always enough by itself\n\nGood auto-layout makes the design easier to review, easier to resize, and easier to fix.",
  "canvas-positioning": "# Canvas Positioning\n\nTop-level frame placement is part of the design quality, not an implementation detail.\n\nIf multiple root frames are created at `0,0`, the result is harder to review, harder to compare, and easier to misread as unfinished work.\n\n## Core Principle\n\nEvery top-level frame, section, and stage area must be intentionally placed on the canvas.\n\n- Root nodes should not overlap by default.\n- Final output should be readable from the canvas without opening the layer panel.\n- Review flow should be visible in the spatial layout.\n\n`x` and `y` are required for top-level composition.\n\n## Root Placement Rule\n\nNever create a top-level frame, section, or stage area without explicit `x` and `y`.\n\nBad:\n\n- multiple mockups created at `0,0`\n- component stage dropped on top of final screens\n- cloned artboards left at the source position\n\nGood:\n\n- each root node has planned placement\n- sibling screens are aligned on a shared row or column\n- support material is placed in a separate zone\n\n## Reviewer-First Layout\n\nThe canvas should present work in review order.\n\nRecommended zones:\n\n- top-left: final outputs\n- below final outputs: component stage or supporting assets\n- off to the side: experiments only if they are intentionally preserved\n\nRecommended reading patterns:\n\n- left to right for sibling screens\n- top to bottom for stages or supporting material\n\nA reviewer should understand what to look at first from position alone.\n\n## Positioning System\n\nUse a simple deterministic grid for top-level placement.\n\nSuggested defaults:\n\n- page margin: `80`\n- section start: `x: 80`, `y: 80`\n- screen gap: `80` to `120`\n- section gap: `120` to `160`\n- stage area placed below outputs, not mixed among them\n\nExample:\n\n- Screen 1: `x = 140`, `y = 180`\n- Screen 2: `x = 140 + screenWidth + 80`\n- Screen 3: `x = 140 + 2 * (screenWidth + 80)`\n\nUse formulas, not guesswork.\n\n## Section Rule\n\nCreate sections before screens when the page contains multiple artifacts.\n\n- sections define the review zones\n- screens live inside the final-output section\n- components live inside a dedicated component section\n- experiments should be deleted or isolated\n\nDo not rely on raw frame placement alone when the page has multiple purposes.\n\n## Cloning Rule\n\nWhen cloning a frame for a new mockup:\n\n- always provide new `x` and `y`\n- never leave the clone at the original coordinates\n- treat clone placement as part of the operation, not a later cleanup\n\nIf the clone is meant to be compared to the source, place it in a predictable adjacent position.\n\n## Component Stage Rule\n\nComponent masters and staging frames should not interrupt product review.\n\n- keep them on a separate row or section\n- align them consistently\n- use clear names\n- do not scatter them around the page root\n\nThe component area is support material, not the primary story.\n\n## No Root Chaos\n\nAvoid these patterns:\n\n- orphan text nodes at the page root\n- stray failed-attempt frames\n- partially overlapping screens\n- mixed final and draft work in the same row\n- invisible spatial logic\n\nIf root nodes cannot be understood at a glance, the canvas is not reviewer-friendly.\n\n## Verification Checklist\n\nBefore considering the canvas organized, verify:\n\n1. Are all top-level frames and sections placed with explicit `x` and `y`?\n2. Does the canvas show a clear reading order?\n3. Are final outputs separated from components and experiments?\n4. Can a reviewer compare sibling screens without panning unpredictably?\n5. Are clones placed intentionally instead of stacked on the source?\n6. Are there any leftover root nodes that should be deleted?\n\nIf the answer to any of these is no, the page layout is unfinished.\n\n## Figma and Vibma Notes\n\nWhen working through Vibma:\n\n- always pass `x` and `y` on top-level `frames.create`, `pages.create` follow-up layout, and `frames.clone`\n- use sections to define review zones early\n- keep a consistent gap system across top-level artifacts\n- verify placement after batch operations, especially after cloning\n- treat `0,0` as a sign that placement was skipped, not as a neutral default\n\nCanvas organization is part of communication quality. A good design on a messy canvas is still harder to review than it should be.",
  "component-architecture": "# Component Architecture\n\nReusable UI should be built as systems, not as screenshots that happen to be reusable once.\n\n## Core Principle\n\nCreate components for repeated behavior, not just repeated appearance.\n\n- A good component captures structure, states, and override points.\n- A bad component preserves the dimensions of the first mockup it was drawn in.\n\n## When Something Must Be a Component\n\nUse a component when any of these are true:\n\n- it appears more than once on a page\n- it will appear across multiple pages\n- it has meaningful states\n- it accepts different content in the same structure\n- it should stay consistent over time\n\nTypical examples:\n\n- buttons\n- inputs\n- nav items\n- cards\n- table rows\n- badges\n- dialogs\n\n## When to Use a Variant Set\n\nUse a variant set when the structure is the same but the state changes.\n\nGood variant dimensions:\n\n- `State`: default, active, disabled, error\n- `Style`: primary, secondary, ghost\n- `Tone`: neutral, success, warning, danger\n- `Size`: sm, md, lg\n\nDo not use a variant set when the underlying structure meaningfully changes.\n\nIf two nodes behave differently enough that they need different internal layout, they should be separate components.\n\n## Instance Rule\n\nFinal screens should be assembled from instances, not detached duplicates.\n\n- build the component once\n- place instances in layouts\n- override content through properties\n- only detach when the design intentionally stops being shared\n\nIf the screen is composed of clones instead of instances, the design is not maintainable enough.\n\n## Internal Layout Rule\n\nComponent roots should describe behavior, not specimen size.\n\n- the component root should usually be usable with `FILL` in context\n- structural inner frames should usually use `FILL`\n- content-sized leaves can use `HUG`\n- fixed size should be reserved for true fixed parts like icons or small controls\n\nExample:\n\n- nav item root: `FILL`\n- label rail: `FILL`\n- label text: `FILL`\n- count pill: `HUG`\n- icon: fixed\n\n## Property Rule\n\nExposed properties must be semantic.\n\nGood property names:\n\n- `label`\n- `value`\n- `helper_text`\n- `title`\n- `description`\n- `meta`\n- `cta`\n\nBad property names:\n\n- raw text content used as property name\n- generated ids\n- names that only make sense in the first specimen\n\n## State Coverage\n\nEach important component should include the minimum states needed for product work.\n\nExamples:\n\n- button: default, secondary or ghost, disabled if used\n- input: default, focus or active, error, disabled if used\n- nav item: default and active\n- badge: neutral and at least one semantic status\n\nDo not build only the happy path if the component clearly needs states.\n\n## Avoid Over-Varianting\n\nNot every difference should be a variant.\n\nUse variants for stable, repeatable state dimensions. Do not add variants for one-off content or page-specific copy.\n\nIf a difference is just text, prefer a text property.\n\n## Verification Checklist\n\nBefore considering a component done, verify:\n\n1. Is it used as an instance in final screens?\n2. Does it support the needed states?\n3. Are the exposed properties semantic?\n4. Do the internals adapt to the parent instead of forcing a specimen width?\n5. Is the component root reusable across multiple pages without manual repair?\n\nIf the answer to any of these is no, the component definition is incomplete.\n\n## Figma and Vibma Notes\n\nWhen building through Vibma:\n\n- create clean source frames before converting to components\n- expose text properties intentionally\n- inspect property definitions before mass overrides\n- use variant sets for true state dimensions\n- build screens from `instances.create`, not `frames.clone`\n\nIf a component only works because each instance is manually resized or patched, the architecture is too weak.",
  "component-placement": "# Component Placement\n\nReusable components should be easy to inspect without interrupting review of final screens.\n\n## Core Principle\n\nComponent masters belong in a clearly defined support zone, not mixed into the primary product canvas.\n\n- final outputs tell the story\n- component masters support the story\n- experiments should not compete with either\n\n## Placement Rule\n\nPlace component masters and staging frames in a dedicated area.\n\nRecommended pattern:\n\n- final screens in the primary review zone\n- component stages in a separate section below or beside the screens\n- experiments isolated or removed\n\nDo not scatter masters across the page root.\n\n## Stage Rule\n\nCreate stages by category.\n\nExamples:\n\n- `Button Stage`\n- `Input Stage`\n- `Navigation Stage`\n- `Card Stage`\n- `Table Stage`\n\nEach stage should hold only closely related components.\n\n## Alignment Rule\n\nComponent areas should be arranged as deliberately as screens.\n\n- align stages on a shared row or column\n- use consistent gaps\n- give each stage a clear title\n- avoid mixed scales in the same stage\n\nIf the component area looks like leftovers, review quality drops.\n\n## Distance Rule\n\nKeep components close enough to be discoverable, but far enough away to avoid confusion with final output.\n\nGood:\n\n- a section directly below the screens\n- a library zone to the right of the screens\n\nBad:\n\n- component masters between two review screens\n- staging frames mixed into a final mockup row\n\n## Example Rule\n\nKeep examples and masters separate when possible.\n\n- masters show the reusable source\n- example instances show real usage\n\nThe reviewer should be able to tell which is which at a glance.\n\n## Checklist\n\nBefore considering component placement done, verify:\n\n1. Are component masters grouped in a dedicated zone?\n2. Are stages named clearly?\n3. Are final screens visually separate from component sources?\n4. Can a reviewer inspect the component area without losing the review flow?\n5. Are stray masters or experiments left at the page root?\n\nIf the answer to any of these is no, the canvas needs another organization pass.\n\n## Figma and Vibma Notes\n\nWhen working through Vibma:\n\n- create a component section before creating many masters\n- place stages with explicit `x` and `y`\n- keep stage widths and gaps consistent\n- convert source nodes in place inside the stage area\n- delete failed attempts instead of leaving them around the page\n\nComponent placement is successful when reviewers can find the library quickly without mistaking it for final output.",
  "content-and-states": "# Content And States\n\nA polished layout with unrealistic content or missing states is still incomplete.\n\n## Core Principle\n\nUse realistic content and show the states that matter for the product.\n\n- content should feel product-like\n- states should reflect actual usage\n- default-only design is rarely enough\n\n## Content Rule\n\nAvoid placeholder content in final review work.\n\nPrefer:\n\n- plausible product names\n- realistic labels\n- short but credible descriptions\n- believable owners, counts, dates, and statuses\n\nAvoid:\n\n- lorem ipsum\n- repeated identical cards\n- empty labels used only to satisfy layout\n\nWeak content makes strong structure harder to evaluate.\n\n## State Rule\n\nEach key component should show the minimum meaningful state coverage.\n\nExamples:\n\n- button: primary and at least one alternate state\n- nav item: default and active\n- input: default and error or active\n- badge: neutral and semantic status\n- queue row: normal and at least one high-priority state through content or tone\n\nDo not show only the clean happy path when the product clearly depends on state changes.\n\n## Screen Rule\n\nEach screen should communicate a concrete scenario.\n\nExamples:\n\n- overview screen with live metrics\n- review screen with blockers\n- pipeline screen with scheduling pressure\n\nIf the screen has no scenario, it becomes a generic layout demo instead of a useful mockup.\n\n## Empty And Edge Cases\n\nNot every page needs every state, but the design system should prove it can handle:\n\n- empty lists\n- long labels\n- errors\n- warnings\n- blocked states\n- disabled actions\n\nAt least one of these should usually appear in component or example coverage.\n\n## Copy Discipline\n\nGood UI copy is:\n\n- short\n- specific\n- scannable\n- role-appropriate\n\nAvoid clever filler text that looks polished but explains nothing.\n\n## Checklist\n\nBefore considering content and state coverage done, verify:\n\n1. Does the screen show a believable scenario?\n2. Are repeated elements differentiated with real content?\n3. Do the key components show the states they need?\n4. Is there evidence the system can handle warnings, blockers, or errors?\n5. Would a reviewer learn product behavior from the examples?\n\nIf the answer to any of these is no, the work is too shallow.\n\n## Figma and Vibma Notes\n\nWhen working through Vibma:\n\n- use instance overrides for realistic content\n- avoid detached copies just to change text\n- inspect property names before large override passes\n- clean obvious stale layer names when the tool allows it\n\nA strong mockup communicates both structure and product reality.",
  "naming": "# Naming\n\nNaming is part of the design system. Reviewers and future editors should understand the file without decoding placeholder names.\n\n## Core Principle\n\nEvery meaningful node should be named for its role.\n\n- names should describe purpose\n- names should reduce ambiguity\n- names should help both review and reuse\n\n## Structural Naming\n\nUse semantic names for pages, sections, frames, and groups.\n\nGood:\n\n- `Desktop Mockups`\n- `Mockup Components`\n- `Workspace Overview`\n- `Primary Nav`\n- `Review Queue Panel`\n\nBad:\n\n- `Frame 1`\n- `Group 2`\n- `Rectangle 7`\n- `Auto layout`\n\n## Component Naming\n\nComponent names should describe the reusable object.\n\nGood:\n\n- `Button`\n- `Sidebar Item`\n- `Metric Tile / Default`\n- `Queue Row / Default`\n\nVariant components should use clear dimensions:\n\n- `State=Active`\n- `Style=Primary`\n- `Tone=Warning`\n\n## Property Naming\n\nExposed component properties must be semantic.\n\nGood:\n\n- `label`\n- `value`\n- `title`\n- `description`\n- `helper_text`\n- `owner`\n- `time`\n\nBad:\n\n- property names copied from raw text content\n- generated ids\n- names that only make sense in one specimen\n\n## Text Layer Naming\n\nUse the right naming style for the situation:\n\n- semantic names for stable structural text inside components\n- content-synced names for free text only when that improves review and the tool supports clean syncing\n\nDo not leave a component property named after the first sentence that happened to be typed into it.\n\n## Section And Stage Naming\n\nCanvas organization should be readable from node names.\n\nGood:\n\n- `Desktop Mockups`\n- `Component Stage`\n- `Nav Item Stage`\n- `Examples`\n\nBad:\n\n- `Stuff`\n- `Other`\n- `Copy`\n- `Working Area`\n\n## Naming Consistency\n\nChoose one naming pattern and keep it stable.\n\nExamples:\n\n- title case for pages, sections, frames, and components\n- lowercase snake case for text properties when useful\n- consistent variant property names such as `State`, `Size`, `Style`, `Tone`\n\nInconsistent naming makes good structure look weaker than it is.\n\n## Checklist\n\nBefore considering naming done, verify:\n\n1. Are there any default names left?\n2. Do component names describe reusable objects?\n3. Are variant names clear and stable?\n4. Are exposed properties semantic?\n5. Can a reviewer understand the page from names alone?\n\nIf the answer to any of these is no, naming needs another pass.\n\n## Figma and Vibma Notes\n\nWhen working through Vibma:\n\n- rename source nodes before converting them into components when possible\n- inspect generated property names after `exposeText`\n- clean up stale names after instance overrides if the workflow allows it\n- do not accept successful creation as proof of good naming\n\nGood names reduce review time and improve edit safety.",
  "responsive-designs": "# Responsive Designs\n\nResponsiveness is the default for web-facing design. A layout is not considered complete if it only works at the specimen width it was first drawn at.\n\n## Core Principle\n\nSet layout from the top down.\n\n- Parent containers define structure and available space.\n- Children adapt to the parent.\n- Do not let container width be determined by child content unless that is the explicit goal.\n\nIn practice:\n\n- structural frames are usually `FIXED` or token-driven at the shell level\n- container children usually use `FILL`\n- leaf content can use `HUG`\n\n## Sizing Rules\n\nUse `FIXED` when the element is a layout boundary:\n\n- page frame\n- app shell\n- sidebar width\n- topbar height\n- modal max width\n\nUse `FILL` when the element should respond to its parent:\n\n- main content next to a sidebar\n- navigation stacks inside a sidebar\n- cards inside responsive columns\n- component instances placed inside layout containers\n- text blocks that should wrap within the container\n\nUse `HUG` only when the element is content-sized by intent:\n\n- icon\n- badge pill\n- count chip\n- button label\n- small metadata cluster\n- branding lockup\n\nAvoid using `HUG` on structural containers.\n\n## Component Rule\n\nDo not encode specimen width into a reusable component unless the component is truly fixed-size.\n\nBad:\n\n- a sidebar item component created at `1270px` wide, then resized down in instances\n\nGood:\n\n- the sidebar item defines internal layout behavior\n- the instance uses `FILL` in its parent nav stack\n- icon stays fixed\n- label fills remaining space\n- count pill hugs content\n\nThe component should describe behavior, not just preserve the dimensions of the first mockup it was drawn in.\n\n## Sidebar Example\n\nRecommended sidebar pattern:\n\n- `Sidebar`: `FIXED` width\n- `Main Column`: `FILL`\n- `Primary Nav`: `FILL`\n- `Sidebar Item` instance: `FILL`\n- item left cluster: `FILL`\n- item label: `FILL` with truncation or wrapping based on product need\n- item count/badge: `HUG`\n- footer container: `FILL`\n- footer body text: `FILL` with height auto-resize\n\nIf the sidebar width changes, the nav items and footer should follow automatically without manual resizing.\n\n## Text Behavior\n\nText must be sized for the container it lives in.\n\n- Long-form body copy should usually use fill width and grow in height.\n- Single-line labels can fill horizontally and truncate when needed.\n- Do not allow text to force container width unless the component is intentionally content-sized.\n\n## Design Review Checks\n\nBefore considering a layout done, verify:\n\n1. If the parent gets wider, do the children expand correctly?\n2. If the parent gets narrower, do labels wrap or truncate intentionally?\n3. Does the main content fill the remaining space after shell widths change?\n4. Are there any components whose master width is just a leftover specimen size?\n5. Are structural containers using `FILL` where they should, instead of fixed child widths?\n\nIf resizing one container requires hand-fixing multiple children, the structure is not responsive enough.\n\n## Exceptions\n\nExceptions are valid, but should be deliberate:\n\n- intrinsic branding marks\n- chips, pills, and compact controls\n- menus or popovers with content-driven sizing\n- small inline metadata groups\n- tightly controlled fixed-size widgets\n\nException logic should stay local. It should not leak upward and dictate the size of major layout containers.\n\n## Figma and Vibma Notes\n\nWhen implementing responsive layouts in Figma through Vibma:\n\n- set shell widths explicitly at the parent level\n- prefer `layout.layoutSizingHorizontal: \"FILL\"` on container children\n- keep leaf nodes on `HUG` or fixed size\n- test by changing the parent width after assembly\n- treat a successful resize test as part of verification, not as optional polish\n\nIf a component only works after instance-level resizing, the component definition is not finished.",
  "token-discipline": "# Token Discipline\n\nTokens are the system. Screens and components should consume them, not compete with them.\n\n## Core Principle\n\nDefine reusable design decisions once, then bind UI to those decisions everywhere.\n\n- variables are the source of truth\n- styles are optional convenience layers\n- hardcoded values are exceptions, not defaults\n\n## What Must Be Tokenized\n\nTokenize any value that is part of the design language:\n\n- colors\n- spacing\n- radius\n- stroke width\n- opacity when reused\n- key layout dimensions\n- typography styles\n\nDo not hardcode production UI values for these unless there is a clear reason.\n\n## Semantic Naming\n\nPrefer semantic token names over literal ones.\n\nGood:\n\n- `bg/canvas`\n- `surface/raised`\n- `text/default`\n- `border/strong`\n- `brand/solid`\n\nLess useful:\n\n- `green-500`\n- `gray-light-2`\n- `card-beige`\n\nSemantic names survive theme changes and product growth better.\n\n## Source of Truth Rule\n\nUse variables as the main source of truth for reusable values.\n\n- bind fills and strokes to color variables\n- bind radius and spacing to numeric variables where supported\n- use text styles for reusable typography systems\n\nPaint styles are allowed as convenience or library references, but they should not replace the token layer.\n\n## Build Order\n\nUse this order:\n\n1. create variable collections and modes\n2. create semantic variables\n3. create text styles and optional paint styles\n4. bind components to tokens\n5. assemble screens from token-bound components\n\nIf screens come before tokens, the system usually ends up partially hardcoded.\n\n## Theme Verification\n\nTheme support should be verified on identical structure.\n\nRecommended method:\n\n- build one surface\n- clone it\n- pin the clone to a different variable mode\n- verify that the same components invert correctly\n\nDo not rebuild the same screen twice if the goal is mode verification.\n\n## Hardcoded Value Rule\n\nHardcoded values are acceptable only when one of these is true:\n\n- the value is one-off and intentionally not part of the system\n- the tooling cannot bind the property yet\n- the value is purely temporary during exploration\n\nIf a hardcoded value remains in final UI, it should be a conscious exception.\n\n## Checklist\n\nBefore considering token work done, verify:\n\n1. Are the main colors variable-bound?\n2. Are text styles used consistently?\n3. Are spacing and radius tokenized where the tool supports it?\n4. Are semantic names used instead of literal color names?\n5. Can the theme be validated by switching modes on identical structure?\n\nIf the design changes require editing many nodes directly, the token layer is not strong enough.\n\n## Figma and Vibma Notes\n\nWhen working through Vibma:\n\n- use `fillVariableName` and `strokeVariableName` for color\n- use numeric variable bindings where available, such as radius and spacing\n- pin theme modes with `explicitMode: { collectionId, modeId }`\n- run lint for hardcoded colors after assembly\n- if a property cannot yet be bound cleanly, document the exception\n\nToken discipline is successful when a theme or system update changes the UI through bindings, not through manual repainting.",
  "verification-and-cleanup": "# Verification And Cleanup\n\nWork is not done when the shapes exist. It is done when the file is verified and the canvas is clean.\n\n## Core Principle\n\nEvery delivery should end with checks and cleanup.\n\n- verify behavior\n- verify structure\n- verify token usage\n- remove noise\n\n## Required Checks\n\nRun the checks that matter for the artifact:\n\n- hardcoded color check\n- text style check\n- contrast check\n- responsive resize check\n- theme or mode check when multiple modes exist\n- component reuse check\n\nDo not assume the file is clean because creation calls succeeded.\n\n## Responsive Check\n\nResize a meaningful parent and verify:\n\n- children fill correctly\n- labels wrap or truncate intentionally\n- sibling areas rebalance correctly\n\nIf the design breaks during a basic resize test, it is not complete.\n\n## Theme Check\n\nIf the file supports multiple modes:\n\n- verify on identical structure\n- check key screens in both modes\n- confirm semantic bindings, not just visual similarity\n\n## Canvas Cleanup\n\nRemove or isolate:\n\n- orphan root nodes\n- failed attempts\n- overlapping drafts\n- unused staging fragments\n- leftover clones from experiments\n\nA clean page is easier to review and safer to extend.\n\n## Naming Cleanup\n\nBefore finishing:\n\n- remove default names\n- improve bad property names\n- clean obvious stale text names when practical\n\nDo not leave the file in a “works, but messy” state if cleanup is straightforward.\n\n## Checklist\n\nBefore considering the task done, verify:\n\n1. Do key lint checks pass?\n2. Have you resized at least one important parent container?\n3. Have you verified theme behavior when relevant?\n4. Are components reused instead of cloned?\n5. Is the page root free of stray nodes and failed attempts?\n\nIf the answer to any of these is no, the task is not closed.\n\n## Figma and Vibma Notes\n\nWhen working through Vibma:\n\n- use focused lint rules instead of only a giant all-rules pass\n- verify after clone, swap, and large batch updates\n- inspect the page root before finishing\n- delete stray nodes created by failed dependent operations\n\nVerification is what turns generation into deliverable work.",
  "vibma-workflow": "# Vibma Workflow\n\nVibma is powerful enough for serious design work, but weaker models need explicit operating rules to avoid preventable mistakes.\n\n## Core Principle\n\nWork with the tool in a predictable sequence.\n\n- read before writing\n- create parents before children\n- verify after significant mutations\n\n## Session Rule\n\nConfirm the connection before doing anything substantial.\n\n- ensure the channel is joined\n- confirm the current page and document\n- treat a reset session as normal, not exceptional\n\nIf the channel is missing, reconnect first.\n\n## Read-Before-Write Rule\n\nInspect existing pages, components, variables, and styles before creating new ones.\n\nDo not guess:\n\n- existing token names\n- component property names\n- page structure\n- current selection\n\nGuessing is one of the fastest ways to create duplicate systems or invalid overrides.\n\n## Parent-First Rule\n\nAlways create parent containers before dependent children.\n\nGood:\n\n- create section\n- create frame in section\n- create child stacks in frame\n- create text inside the stacks\n\nBad:\n\n- create parent and child in parallel when the child depends on the parent id\n\nDependent creates should not be parallelized.\n\n## Batch Rule\n\nBatch independent operations, but chunk large writes.\n\n- keep large updates in manageable groups\n- verify after big batches\n- do not assume a very large batch will be accepted\n\nIf a write affects many nodes, chunk it intentionally.\n\n## Placement Rule\n\nAlways pass `x` and `y` for top-level nodes and clones.\n\n- sections need explicit placement\n- screen roots need explicit placement\n- clones need explicit new placement\n\nDo not accept `0,0` stacking as a neutral default.\n\n## Layout Update Rule\n\nFor layout sizing updates, prefer the explicit layout payload.\n\nExamples:\n\n- `layout.layoutSizingHorizontal`\n- `layout.layoutSizingVertical`\n- `layout.itemSpacing`\n\nDo not assume that a top-level shortcut field changed the actual node just because the write returned `ok`.\n\n## Instance Rule\n\nInspect component properties before bulk overrides.\n\n- verify property names\n- verify variant dimensions\n- override through instance properties, not detached edits\n\nIf a property name is unclear, inspect first.\n\n## Verification Rule\n\nAfter important operations, check the result directly:\n\n- after clone\n- after swap\n- after explicit mode pinning\n- after large layout refactors\n- after token-binding passes\n\nSuccessful writes are not enough. Read back the node.\n\n## Cleanup Rule\n\nIf a dependent operation fails:\n\n- clean stray nodes\n- remove root-level leftovers\n- do not leave failed attempts on the page\n\nMess from failed writes compounds quickly.\n\n## Checklist\n\nBefore considering a Vibma task done, verify:\n\n1. Was the session connected and verified?\n2. Did you read the existing structure before writing?\n3. Were parents created before children?\n4. Were large writes chunked reasonably?\n5. Were top-level nodes placed intentionally?\n6. Were important mutations verified by reading back the node?\n\nIf the answer to any of these is no, the workflow is too fragile.\n\nWeaker models improve significantly when Vibma is treated as a disciplined build system instead of a free-form drawing surface."
};

/** Resolve a guidelines query. */
export function resolveGuideline(topic?: string): string {
  if (!topic) {
    const dir = ["# Design Guidelines", ""];
    for (const g of guidelinesList) {
      dir.push("  " + g.name.padEnd(30) + g.title);
    }
    dir.push("");
    dir.push('Use guidelines(topic: "<name>") for full guideline text.');
    return dir.join("\n");
  }
  const content = guidelinesContent[topic];
  if (content) return content;
  const names = guidelinesList.map(g => g.name);
  return "Unknown guideline: " + topic + ". Available: " + names.join(", ");
}
